{
    "level": "A1",
    "intro": "In this topic, you will learn <strong>personal and object pronouns</strong>, the two main forms that show who does the action and who does it. receives.",
    "rules": [
        {
            "label": "Subject",
            "color": "emerald",
            "text": "<strong>Subject pronouns</strong> - who acts:",
            "example": "I work. She reads. They play."
        },
        {
            "label": "Object",
            "color": "blue",
            "text": "<strong>Object pronouns</strong> - who/what:",
            "example": "Call me. I see him. Tell us."
        },
        {
            "label": "Position",
            "color": "amber",
            "text": "<strong>Position in the sentence</strong>:",
            "example": "Subject before the verb, Object after."
        }
    ]
}

{
    "title": "1. Two Forms of Personal Pronouns by verb)",
    "intro": "Особові займенники мають дві форми залежно від їхньої ролі у реченні:",
    "items": [
        {
            "label": "Subject",
            "title": "Підметові",
            "subtitle": "I, you, he, she, it, we, they — виконують дію (перед дієсловом)"
        },
        {
            "label": "Object",
            "title": "Object",
            "subtitle": "me, you, him, her, it, us, them — receive an action (after the verb)"
        }
    ]
}

{
    "title": "2. Subject Pronouns - Subject pronouns",
    "sections": [
        {
            "label": "What are subject pronouns?",
            "color": "emerald",
            "description": "Subject pronouns are used as the <strong>subject of a sentence</strong> - they show who performs the action. Stand <strong>before the verb</strong>.",
            "examples": [
                {
                    "en": "I work every day.",
                    "ua": "Я працюю щодня."
                },
                {
                    "en": "You are smart.",
                    "ua": "Ти розумний / Ви розумні."
                },
                {
                    "en": "He lives in Kyiv.",
                    "ua": "Він живе в Києві."
                },
                {
                    "en": "She speaks English.",
                    "ua": "She speaks English."
                },
                {
                    "en": "It is a cat.",
                    "ua": "It is a cat."
                },
                {
                    "en": "We study together.",
                    "ua": "We study together."
                },
                {
                    "en": "They play football.",
                    "ua": " football."
                }
            ]
        },
        {
            "label": "I is me",
            "color": "sky",
            "description": "<strong>I</strong> (me) is always capitalized, even within a sentence.",
            "examples": [
                {
                    "en": "I like coffee.",
                    "ua": "I love coffee."
                },
                {
                    "en": "My friend and I went to the park.",
                    "ua": "My friend and I went to the park."
                },
                {
                    "en": "I am a student.",
                    "ua": "I am a student."
                }
            ],
            "note": "📌 Always I (uppercase letter), never i (lowercase)!"
        },
        {
            "label": "You are you / вы",
            "color": "purple",
            "description": "<strong>You</strong> (you/you) is a universal form for singular and plural, formal and informal address.",
            "examples": [
                {
                    "en": "You are my friend. (you)",
                    "ua": "You are my friend."
                },
                {
                    "en": "You are welcome here. (you)",
                    "ua": "You are always welcome here."
                },
                {
                    "en": "Are you ready?",
                    "ua": "You are ready? Are you ready?"
                }
            ]
        },
        {
            "label": "He, She, It — він, вона, воно",
            "color": "amber",
            "description": "<strong>He</strong> — чоловічий рід, <strong>she</strong> — жіночий рід, <strong>it</strong> — для тварин, предметів, абстрактних понять.",
            "examples": [
                {
                    "en": "He is my brother.",
                    "ua": "Він мій брат."
                },
                {
                    "en": "He works in a bank. (the dog → it), weather, time, distance.",
                    "ua": "Вона працює в банку."
                },
                {
                    "en": "It is raining.",
                    "ua": "Йде дощ."
                },
                {
                    "en": "It is a good book.",
                    "ua": "Це хороша книга."
                }
            ],
            "note": "📌 It використовуємо для тварин (the dog → it), погоди, часу, відстані."
        },
        {
            "label": "We, They - we, they",
            "color": "rose",
            "description": "<strong>We</strong> (we) is a group that includes me. <strong>They</strong> (they) is a group that does not include me.",
            "examples": [
                {
                    "en": "We love this city.",
                    "ua": "We love this city."
                },
                {
                    "en": "They are students.",
                    "ua": "They are students."
                },
                {
                    "en": "We go to school together.",
                    "ua": "We we go to school together."
                },
                {
                    "en": "They live in London.",
                    "ua": "They live in London."
                }
            ]
        }
    ]
}

{
    "title": "3. Object Pronouns - Object pronouns",
    "sections": [
        {
            "label": "What are object pronouns?",
            "color": "blue",
            "description": "Object pronouns are used as an <strong>appendix</strong> - they show who/what the action is aimed at. Stand <strong>after a verb or a preposition</strong>.",
            "examples": [
                {
                    "en": "Call me later.",
                    "ua": "Call me later."
                },
                {
                    "en": "I see you.",
                    "ua": "I see you / you."
                },
                {
                    "en": "She loves him.",
                    "ua": "She loves him."
                },
                {
                    "en": "Tell her the truth.",
                    "ua": "Tell her the truth."
                },
                {
                    "en": "Give it to me.",
                    "ua": "Give it to me."
                },
                {
                    "en": "They invited us.",
                    "ua": " us."
                },
                {
                    "en": "I know them well.",
                    "ua": "I know them well."
                }
            ]
        },
        {
            "label": "After verbs",
            "color": "sky",
            "description": "Object pronouns come after the verb as a direct or indirect object.",
            "examples": [
                {
                    "en": "I like him.",
                    "ua": "He likes me."
                },
                {
                    "en": "Help me, please.",
                    "ua": "Help me, please."
                },
                {
                    "en": "She knows us.",
                    "ua": "She knows us."
                },
                {
                    "en": "I told them everything.",
                    "ua": "I told them everything."
                }
            ]
        },
        {
            "label": "After prepositions",
            "color": "purple",
            "description": "After prepositions (with, for, to, about, at, etc.) we always use object pronouns</strong>.",
            "examples": [
                {
                    "en": "Come with me.",
                    "ua": "Come with me."
                },
                {
                    "en": "This is for you.",
                    "ua": "This is for you / you."
                },
                {
                    "en": "Talk to him.",
                    "ua": "Talk to him."
                },
                {
                    "en": "She is thinking about her.",
                    "ua": "She is thinking about her."
                },
                {
                    "en": "They are looking at us.",
                    "ua": "They are looking at us."
                }
            ],
            "note": "📌 Never I after with, for, to — always me!"
        },
        {
            "label": "In short answers",
            "color": "amber",
            "description": "In short answers we use <strong>object pronouns</strong>.",
            "examples": [
                {
                    "en": "Who did it? — Me. (not I!)",
                    "ua": "Who did this? — I."
                },
                {
                    "en": "Who wants coffee? - Me! (spoken)",
                    "ua": "Who wants coffee? — Me!"
                },
                {
                    "en": "Who is she talking to? — Him.",
                    "ua": "Who is she talking to? — With him."
                }
            ],
            "note": "📌 Formally correct: It's I / It was he. But colloquially: It's me / It was him."
        }
    ]
}

{
    "title": "4. Comparison table: Subject vs Object",
    "intro": "Full table of personal pronouns in two forms:",
    "rows": [
        {
            "en": "I",
            "ua": "me (subject)",
            "note": "me — me, me (appendix)"
        },
        {
            "en": "you",
            "ua": "you (subject)",
            "note": "you — you (appendix)"
        },
        {
            "en": "he",
            "ua": "he (subject)",
            "note": "him is his, him (appendix)"
        },
        {
            "en": "she",
            "ua": "she (subject)",
            "note": "her is her, her (appendix)"
        },
        {
            "en": "it",
            "ua": "it (subject)",
            "note": "it is his/her (appendix)"
        },
        {
            "en": "we",
            "ua": "we (subject)",
            "note": "us is us (appendix)"
        },
        {
            "en": "they",
            "ua": "they (subject)",
            "note": "them — them, them (appendix)"
        }
    ],
    "warning": "📌 You and it have the same form as the subject and as the adjunct!"
}

{
    "title": "5. How do you decide which form to use?",
    "sections": [
        {
            "label": "Ask: Who? What? (Who called? - He)",
            "color": "emerald",
            "description": "Якщо можна запитати <strong>Хто?</strong> або <strong>Що?</strong> (підмет) — використовуй subject pronoun.",
            "examples": [
                {
                    "en": "He called. (Хто подзвонив? — Він)",
                    "ua": "He called."
                },
                {
                    "en": "She is here. (Who is here? - She)",
                    "ua": "She is here."
                },
                {
                    "en": "They won. (Who won? - They)",
                    "ua": "They won."
                }
            ]
        },
        {
            "label": "Ask: Who? Whom? What?",
            "color": "blue",
            "description": "If I may ask <strong>Who? Whom? What?</strong> (appendix) — use object pronoun.",
            "examples": [
                {
                    "en": "He called me. (Who called? - Me)",
                    "ua": "He called me."
                },
                {
                    "en": "I see her. (Who do I see? - Her)",
                    "ua": "I see her."
                },
                {
                    "en": "Tell them. (To whom to tell? — Them)",
                    "ua": "Tell them."
                }
            ]
        },
        {
            "label": "Sentence position",
            "color": "amber",
            "description": "<strong>Before the verb</strong> — subject, <strong>after the verb/preposition</strong> — object.",
            "examples": [
                {
                    "en": "I like him. (not He like I)",
                    "ua": "Я → subject, him → object"
                },
                {
                    "en": "She helps us. (not Her help we)",
                    "ua": "She → subject, us → object"
                },
                {
                    "en": "They know me. (not Them know I)",
                    "ua": "They → subject, me → object"
                }
            ],
            "note": "📌 If in doubt, think about the position in the sentence!"
        }
    ]
}

{
    "title": "6. Typical mistakes of Ukrainian speakers",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Confusion of subject and object forms.",
            "wrong": "Me and John went to the park. / Her is my friend.",
            "right": " ✅ <span class="font-mono">John and I went to the park. She is my friend. / This is for him.</span>"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Subject після прийменника.",
            "wrong": "Come with I. / This is for he.",
            "right": "✅ <span class="font-mono">Come with me. / This is for him.</span>"
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Object before the verb.",
            "wrong": "Him likes pizza. / Them are students.",
            "right": "​​​​ <span class="font-mono">He likes pizza. / They are students.</span>"
        },
        {
            "label": "Error 4",
            "color": "purple",
            "title": "I with a small letter.",
            "wrong": "Yesterday i went to school.",
            "right": "​​​​ <span class="font-mono">Yesterday I went to school.</span>"
        }
    ]
}

